import{_ as t,o as e,c as r,a2 as o}from"./chunks/framework.xcumbC7K.js";const p=JSON.parse('{"title":"什么是 NovaChart？","description":"","frontmatter":{},"headers":[],"relativePath":"guide/what-is-nova-chart.md","filePath":"guide/what-is-nova-chart.md","lastUpdated":1781997983000}'),l={name:"guide/what-is-nova-chart.md"};function i(h,a,n,s,d,c){return e(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="什么是-novachart" tabindex="-1">什么是 NovaChart？ <a class="header-anchor" href="#什么是-novachart" aria-label="Permalink to &quot;什么是 NovaChart？&quot;">​</a></h1><p>NovaChart 是一个<strong>为初学者设计</strong>的极简图表库。它从 <a href="https://www.chartjs.org/" target="_blank" rel="noreferrer">Chart.js</a> 汲取灵感，但把复杂的 API 砍到只剩最常用的部分。</p><h2 id="一句话定义" tabindex="-1">一句话定义 <a class="header-anchor" href="#一句话定义" aria-label="Permalink to &quot;一句话定义&quot;">​</a></h2><blockquote><p><strong>NovaChart = 配置对象 + 4 种图表 + 3 套主题 + 1 个 <code>.draw()</code> 调用</strong></p></blockquote><h2 id="它解决什么问题" tabindex="-1">它解决什么问题？ <a class="header-anchor" href="#它解决什么问题" aria-label="Permalink to &quot;它解决什么问题？&quot;">​</a></h2><p>学生写网页作业时，想要展示一组数据（比如考试成绩），但：</p><ul><li>❌ Chart.js / ECharts 太复杂，光看文档就头大</li><li>❌ matplotlib 只能在 Python 画，网页展示需要导出图片</li><li>❌ 自己用 Canvas 画，代码量爆炸</li></ul><p><strong>NovaChart 的答案</strong>：8 个字段、3 行核心代码、搞定 4 种图表。</p><h2 id="核心设计原则" tabindex="-1">核心设计原则 <a class="header-anchor" href="#核心设计原则" aria-label="Permalink to &quot;核心设计原则&quot;">​</a></h2><h3 id="_1-一致性-功能多" tabindex="-1">1. 一致性 &gt; 功能多 <a class="header-anchor" href="#_1-一致性-功能多" aria-label="Permalink to &quot;1. 一致性 &gt; 功能多&quot;">​</a></h3><p>四种图表的 config 结构 100% 相同。学会 Bar，等于学会 Line/Pie/Table。</p><h3 id="_2-默认值优先" tabindex="-1">2. 默认值优先 <a class="header-anchor" href="#_2-默认值优先" aria-label="Permalink to &quot;2. 默认值优先&quot;">​</a></h3><p>不填也能跑。<code>title</code> / <code>unit</code> 等都是可选，库会自动选最合理的默认值。</p><h3 id="_3-视觉一致性" tabindex="-1">3. 视觉一致性 <a class="header-anchor" href="#_3-视觉一致性" aria-label="Permalink to &quot;3. 视觉一致性&quot;">​</a></h3><p>主题色不只决定图表颜色，还会自动应用到：网格、坐标轴文字、表格表头、Tooltip、斑马纹。<strong>改一处，全局换肤</strong>。</p><h3 id="_4-单一数据组" tabindex="-1">4. 单一数据组 <a class="header-anchor" href="#_4-单一数据组" aria-label="Permalink to &quot;4. 单一数据组&quot;">​</a></h3><p>三图永远只接受一个 <code>data: [...]</code> 数组。没有“数据集”概念，没有多系列叠加。（Table 可传二维自动识别多行）</p><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><p>✅ <strong>适合</strong>：</p><ul><li>学生网页作业、数据展示</li><li>快速原型、教学演示</li><li>不需要复杂交互的静态可视化</li><li>后端程序员偶尔前端画图</li></ul><p>❌ <strong>不适合</strong>：</p><ul><li>商业级数据大屏（用 ECharts）</li><li>复杂的多维度数据分析（用 D3）</li><li>需要缩放/拖拽的探索式可视化</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>阅读 <a href="/nova-chart/guide/why-nova-chart.html">为什么选择 NovaChart？</a> 了解设计取舍</li><li>直接跳到 <a href="/nova-chart/guide/getting-started.html">快速开始</a> 写第一行代码</li></ul>',24)])])}const _=t(l,[["render",i]]);export{p as __pageData,_ as default};
